var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"신원 확인했습니다.","JPN":"身元を確認しました。","ENG":"Identification completed.","TWN":"已驗證身分。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"즐거운 여행되시길 바랍니다, 스완 양.","JPN":"楽しい旅行を、スワンさん。","ENG":"Have a nice trip, Miss Swan.","TWN":"旅途愉快，史旺。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 고마워요.","JPN":"はい、ありがとうございます。","ENG":"I will. Thank you.","TWN":"好的，謝謝。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"봤어요? 방금 나한테 웃어주는 거.","JPN":"見ました？　今私に微笑んでくれましたよ。","ENG":"Did you see that? She just smiled at me.","TWN":"你看到了嗎？她對我笑了。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"저런 유명한 사람이 매니저도 없이 혼자 움직이네요.","JPN":"あんな有名人がマネージャーもなく一人で行動することもあるんですね。","ENG":"It's odd that such a well-known person is traveling alone without a manager.","TWN":"如此出名的人身邊連一個經紀人也沒有。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"이번 작품만 끝나면 배우활동 잠시 쉴 거라고 했잖아요. 휴가라도 다녀오나 보죠.","JPN":"この作品が終わったら、しばらく女優業は休むって言ってたじゃないですか。バカンスですかね？","ENG":"She mentioned how she was going to take a break from acting after this one, right? Maybe she's going on vacation.","TWN":"她說過拍完現在的作品後會進入休息期，應該是要去度假吧。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"로터스는 휴양지로 삼기엔 꽤 위험한 곳이지 않나요? 거기 사는 사람들도 다른 데로 이주하고 싶어서 난린데.","JPN":"ロータスって、バカンスで行くには危険でしょう？　あそこの住民だって引っ越したがってるのに。","ENG":"Isn't Lotus pretty dangerous to go on vacation, though? Even the residents there are trying their best to move away.","TWN":"去洛德斯度假是不是有些太危險了？連那裡的住民都想趕快搬到別的地區呢。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_A","text":{"KOREA":"그러니까 사람들 시선 피하기엔 딱이죠. 그동안 얼마나 많은 파파라치들에게 시달렸겠어요?","JPN":"だから人目を避けるにはうってつけなんでしょう。今までパパラッチのせいで苦労してただろうし。","ENG":"It's perfect for avoiding people. She must've struggled a lot with all the paparazzi constantly chasing her.","TWN":"所以才會更適合避開群眾視線，她一定受夠了狗仔隊。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WORKER_NPC_AIRPORT_B","text":{"KOREA":"이 사람… 완전히 빠졌구만.","JPN":"この人……完全にファンだな。","ENG":"You're... really smitten, aren't you?","TWN":"你這傢伙……完全迷上她咧。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 대장님.","JPN":"はい、隊長。","ENG":"Yes, Commander.","TWN":"你好，隊長。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Oh?","TWN":"咦？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당연히 안 받을 줄 알았는데, 의외의 반응이네요.","JPN":"絶対に出ないと思ってたのに、意外ですね。","ENG":"I didn't think you'd pick up. This is unexpected.","TWN":"我還以為你肯定不會接呢，真出乎意料。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뻔뻔하게 전화를 거셨으니, 저도 뻔뻔하게 받은 것뿐인 걸요.","JPN":"図々しく電話をかけてきましたので、私も図々しく出ただけです。","ENG":"Well, you were shameless enough to call, so I am being shameless and picking up.","TWN":"你厚著臉皮打了電話，我就厚著臉皮接了。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저와 무슨 대화가 하고 싶은 거죠?","JPN":"なにか私に用件ですか？","ENG":"What did you want to talk about?","TWN":"你想和我談什麼？"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아주 요란스럽게 일을 벌이고 떠났더군요.","JPN":"また盛大にやってくれましたね。","ENG":"You really stirred things up before you left.","TWN":"我看你惹出了不少麻煩呢。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"샤레이드의 시니어를 그런 식으로 처리할 줄은 몰랐어요.","JPN":"シャレードのシニアをあんなふうに処理するとは思いませんでした。","ENG":"I never expected you to take care of Charade's Senior in that manner.","TWN":"沒想到會以那種方式處理查雷德的Senior。"},"stage":{"bg":"CORRIDOR_02","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};